# Sample Python function simulating apron stand allocation
def allocate_stand(aircraft_id, available_stands):
    if aircraft_id in available_stands:
        stand = available_stands[aircraft_id]
        del available_stands[aircraft_id]
        return f"Stand {stand} allocated to {aircraft_id}"
    else:
        return "No available stand found for this aircraft."

# Example usage
stands = {'AA123': 'A1', 'DL456': 'B3'}
print(allocate_stand('AA123', stands))  # Output: Stand A1 allocated to AA123
print(allocate_stand('UA789', stands))  # Output: No available stand found for this aircraft.
